INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7c9b7176-3c87-4125-a796-6ecd64d6a545',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Routing — Parameters, Groups, and Prefix Patterns$escape$,
  $escape$ASP.NET Core's minimal API routing maps HTTP verbs directly to delegates via `MapGet`, `MapPost`, etc. Route parameters are declared with `{braces}` and bound automatically to handler parameters by name. Constraints like `{id:int}` or `{slug:regex(^[a-z-]+$)}` are applied inline — no attribute decoration needed.

Route groups (`MapGroup`) let you share a common prefix and middleware across related endpoints without repetition. Apply `.RequireAuthorization()`, `.WithTags()`, or rate limiting to the group once and every member inherits it. Groups nest cleanly: define a `/api/v1` outer group, then an `/articles` inner group — resulting paths compose automatically.

Controller-based routing still uses `[Route]` and `[ApiController]` attributes, but minimal APIs are preferred for new vertical slices. Use `WithName()` to assign route names for `TypedResults.Created()` link generation. Catch-all segments use `{**remainder}` syntax. Always prefer constrained parameters over manual parsing inside handlers — the framework rejects non-matching requests before your code runs.$escape$,
  $escape$var api = app.MapGroup("/api/v1").RequireAuthorization();
var articles = api.MapGroup("/articles");

articles.MapGet("/", ArticleHandlers.GetAll);

articles.MapGet("/{id:guid}", ArticleHandlers.GetById)
    .WithName("GetArticle");

articles.MapPost("/", ArticleHandlers.Create)
    .WithName("CreateArticle")
    .Produces<ArticleDto>(StatusCodes.Status201Created);

articles.MapGet("/by-slug/{slug:regex(^[[a-z0-9-]]+$)}", ArticleHandlers.GetBySlug);

api.MapGet("/users/{userId:int}/feed", FeedHandlers.GetUserFeed);$escape$,
