INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2d8f3f35-c2c4-4c3a-a462-4eeacbe929cb',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core JWT Validation — Middleware, Claims, and Pitfalls$escape$,
  $escape$ASP.NET Core's `AddJwtBearer` extension wires JWT validation into the authentication middleware pipeline. Configure it in `Program.cs` via `AddAuthentication().AddJwtBearer(...)`, setting `TokenValidationParameters` to control what's verified — issuer, audience, lifetime, and signing key. The middleware decodes the token, validates the signature against your `IssuerSigningKey`, and populates `HttpContext.User` with claims automatically before your endpoint logic runs.

Use `[Authorize]` on controllers or map it inline with `.RequireAuthorization()` on minimal API routes. For role-based or policy-based access, define policies in `AddAuthorization(options => options.AddPolicy(...))` and reference them by name.

A common mistake: forgetting to call `app.UseAuthentication()` before `app.UseAuthorization()`. Swapping the order silently breaks claim population — your endpoints see an unauthenticated user even with a valid token.

For sliding sessions, pair JWT with a refresh token stored in an `HttpOnly` cookie. On expiry, the client hits `/auth/refresh`, which validates the refresh token via a hashed lookup in your DB, then issues a new short-lived JWT. Never extend JWT lifetime as a substitute for proper refresh logic.$escape$,
  $escape$builder.Services
    .AddAuthentication(JwtBearerDefaults.AuthenticationScheme)
    .AddJwtBearer(options =>
    {
        options.TokenValidationParameters = new TokenValidationParameters
        {
            ValidateIssuer = true,
            ValidateAudience = true,
            ValidateLifetime = true,
            ValidateIssuerSigningKey = true,
            ValidIssuer = builder.Configuration["Jwt:Issuer"],
            ValidAudience = builder.Configuration["Jwt:Audience"],
            IssuerSigningKey = new SymmetricSecurityKey(
                Encoding.UTF8.GetBytes(builder.Configuration["Jwt:Key"]!))
        };
    });

app.UseAuthentication();
app.UseAuthorization();

app.MapGet("/me", (ClaimsPrincipal user) => user.Identity!.Name)
   .RequireAuthorization();$escape$,
  $escape$csharp$escape$,
