INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '048afbad-30af-45d2-bca3-646c2a927440',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Testing — Unit vs Integration, HttpClient Mocking, and Test DB Strategy$escape$,
  $escape$ASP.NET Core's WebApplicationFactory<TProgram> is the cornerstone of integration testing — it spins up a real in-memory host with your full middleware pipeline, DI container, and routing, letting you assert end-to-end HTTP behavior without deploying. Unit tests belong to handlers, validators, and pure service logic; keep them fast and dependency-free with Moq or NSubstitute. For outbound HTTP calls, inject IHttpClientFactory and swap in a mock MessageHandler via AddHttpClient().ConfigurePrimaryHttpMessageHandler() in your test — never mock HttpClient directly. For the database, prefer Respawn to reset state between tests against a real PostgreSQL instance rather than EF Core's InMemory provider, which silently ignores relational constraints and gives false confidence. Use a dedicated test connection string via environment variables or appsettings.Testing.json loaded via WebApplicationFactory.WithWebHostBuilder(). Mark integration tests with a custom [Trait("Category", "Integration")] and filter them out of your fast CI unit-test run with dotnet test --filter Category!=Integration.$escape$,
  $escape$public class ApiFactory : WebApplicationFactory<Program>
{
    protected override void ConfigureWebHost(IWebHostBuilder builder)
    {
        builder.ConfigureServices(services =>
        {
            services.RemoveAll<DbContextOptions<AppDbContext>>();
            services.AddDbContext<AppDbContext>(opts =>
                opts.UseNpgsql(Environment.GetEnvironmentVariable("TEST_DB")));

            services.AddHttpClient<IGitHubClient, GitHubClient>()
                .ConfigurePrimaryHttpMessageHandler(() => new MockHttpMessageHandler());
        });
    }
}$escape$,
  $escape$csharp$escape$,
