INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '48b87046-a297-4250-bbf3-28732443c077',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Global Error Handling — Consistent ProblemDetails Responses$escape$,
  $escape$ASP.NET Core 8 ships with built-in ProblemDetails support (RFC 9457). Wire it up once and every unhandled exception returns a structured JSON error — no per-controller try/catch needed.

Register `AddProblemDetails()` and `UseExceptionHandler()` in `Program.cs`. The exception handler middleware catches unhandled exceptions, maps them to `ProblemDetails`, and writes the response. For custom mappings, implement `IProblemDetailsWriter` or use `IExceptionHandler` — the cleaner option in .NET 8 — to intercept specific exception types before the fallback kicks in.

`IExceptionHandler` receives the `HttpContext` and the raw exception. Return `true` to short-circuit, `false` to fall through to the next handler. Chain multiple handlers for `ValidationException`, `NotFoundException`, `UnauthorizedAccessException` etc., each setting the appropriate HTTP status and `ProblemDetails.Type` URI.

Set `ASPNETCORE_ENVIRONMENT=Development` to expose `exception` details in the response; in Production they're stripped automatically. Pair with `IProblemDetailsService.WriteAsync()` for manual ProblemDetails responses inside minimal API endpoints or middleware.$escape$,
  $escape$// Program.cs
builder.Services.AddProblemDetails();
builder.Services.AddExceptionHandler<NotFoundExceptionHandler>();
builder.Services.AddExceptionHandler<ValidationExceptionHandler>();

app.UseExceptionHandler();

// NotFoundExceptionHandler.cs
public sealed class NotFoundExceptionHandler(IProblemDetailsService pds)
    : IExceptionHandler
{
    public async ValueTask<bool> TryHandleAsync(
        HttpContext ctx, Exception ex, CancellationToken ct)
    {
        if (ex is not NotFoundException) return false;
        ctx.Response.StatusCode = StatusCodes.Status404NotFound;
        await pds.WriteAsync(new() { HttpContext = ctx, Exception = ex });
        return true;
    }
}$escape$,
