INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3be19e37-1202-428d-8cea-081951fe1968',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Security — CORS, Rate Limiting, Headers, and Injection in One Pass$escape$,
  $escape$Lock down your ASP.NET Core 8 API by layering four defenses. CORS: call `builder.Services.AddCors()` with a named policy, restrict `WithOrigins()` to known domains, and never use `AllowAnyOrigin()` with `AllowCredentials()` — it throws at startup. Rate limiting: use `AddRateLimiter()` with a fixed-window or token-bucket policy and apply `[EnableRateLimiting("policy-name")]` per endpoint or globally via `app.UseRateLimiter()`. Security headers: ASP.NET Core doesn't ship these by default — use `app.Use()` middleware to set `X-Content-Type-Options: nosniff`, `X-Frame-Options: DENY`, and `Content-Security-Policy`. For injection prevention, never interpolate user input into raw SQL — use EF Core's parameterized LINQ or `FromSqlInterpolated()` (safe) over `FromSqlRaw()` with string concat (dangerous). Bind input through model binding with `[ApiController]` to get automatic `ModelState` validation, and annotate DTOs with `[MaxLength]` and `[RegularExpression]` to reject malformed data before it reaches your business logic.$escape$,
  $escape$builder.Services.AddCors(o => o.AddPolicy("Api", p =>
    p.WithOrigins("https://app.example.com")
     .WithMethods("GET", "POST")
     .AllowCredentials()));

builder.Services.AddRateLimiter(o => o.AddFixedWindowLimiter("default", opts => {
    opts.Window = TimeSpan.FromMinutes(1);
    opts.PermitLimit = 100;
}));

app.Use(async (ctx, next) => {
    ctx.Response.Headers["X-Content-Type-Options"] = "nosniff";
    ctx.Response.Headers["X-Frame-Options"] = "DENY";
    ctx.Response.Headers["Content-Security-Policy"] = "default-src 'self'";
    await next();
});

app.UseCors("Api");
app.UseRateLimiter();$escape$,
  $escape$csharp$escape$,
