INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '71ebc80a-4eef-455f-a703-2537af684b67',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Serialization — DTOs, camelCase, and Null Handling Done Right$escape$,
  $escape$ASP.NET Core's `System.Text.Json` serializer defaults to preserving property name casing, so a C# `UserId` property serializes as `UserId`, not `userId`. Fix this globally in `Program.cs` via `builder.Services.ConfigureHttpJsonOptions(o => o.SerializerOptions.PropertyNamingPolicy = JsonNamingPolicy.CamelCase)`. For snake_case (common in Python-facing APIs), use `JsonNamingPolicy.SnakeCaseLower` (.NET 8+). Always use dedicated request/response DTOs — never expose your EF Core entities directly. Decorate DTOs with `[JsonPropertyName]` when a single property needs a different name than the global policy. For null handling, set `DefaultIgnoreCondition = JsonIgnoreCondition.WhenWritingNull` to strip null fields from responses, reducing payload size. On input, `[Required]` + nullable reference types (`string?`) let the model binder distinguish missing from explicitly-null. Pair this with `[ApiController]` so missing required fields auto-return `400` without manual `ModelState` checks. For versioned APIs where field presence semantics matter, prefer `JsonIgnoreCondition.Never` and explicit null to avoid ambiguity between absent and null.$escape$,
  $escape$// Program.cs
builder.Services.ConfigureHttpJsonOptions(options =>
{
    var json = options.SerializerOptions;
    json.PropertyNamingPolicy = JsonNamingPolicy.CamelCase;
    json.DefaultIgnoreCondition = JsonIgnoreCondition.WhenWritingNull;
});

// Response DTO
public record UserResponse(
    int Id,
    string DisplayName,
    [property: JsonPropertyName("avatar_url")] string? AvatarUrl
);

// Request DTO
public record CreateUserRequest(
    [Required] string DisplayName,
    string? Bio
);$escape$,
  $escape$csharp$escape$,
