INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b36b1abf-0aa8-4413-a7d9-425fd2272aa2',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Configuration — Env Vars, Typed Settings, and Secrets Done Right$escape$,
  $escape$ASP.NET Core's configuration system layers sources in priority order: appsettings.json → appsettings.{Environment}.json → environment variables → command-line args. Environment variables override file-based config automatically — no extra code needed. Bind sections to strongly-typed classes using the Options pattern: register with `builder.Services.Configure<MySettings>(builder.Configuration.GetSection("MySettings"))`, then inject `IOptions<MySettings>` or `IOptionsSnapshot<MySettings>` (reloads on change). For secrets, never commit sensitive values. In development, use `dotnet user-secrets init` and `dotnet user-secrets set "MySettings:ApiKey" "abc123"` — stored in `~/.microsoft/usersecrets/`. In production, prefer Azure Key Vault via `builder.Configuration.AddAzureKeyVault(...)` or environment variables injected by your container orchestrator. Validate options at startup using `ValidateDataAnnotations()` and `ValidateOnStart()` to catch missing secrets before the app serves traffic — not at runtime when a request fails.$escape$,
  $escape$// Program.cs
builder.Services.Configure<StripeSettings>(
    builder.Configuration.GetSection("Stripe"))
    .ValidateDataAnnotations()
    .ValidateOnStart();

// StripeSettings.cs
public class StripeSettings
{
    [Required] public string SecretKey { get; init; } = default!;
    [Required] public string WebhookSecret { get; init; } = default!;
}

// Usage in service
public class PaymentService(IOptions<StripeSettings> opts)
{
    private readonly StripeSettings _stripe = opts.Value;
}$escape$,
  $escape$csharp$escape$,
