INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7beaef8d-1c0f-475d-bd1e-1e4e2a55e718',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Logging — Structured Logs, Correlation IDs, and Request Middleware$escape$,
  $escape$ASP.NET Core's built-in `ILogger<T>` supports structured logging out of the box. Instead of string interpolation, use message templates so log sinks (Serilog, OpenTelemetry) can index named properties: `_logger.LogInformation("Order {OrderId} placed by {UserId}", orderId, userId)`. This keeps logs queryable in tools like Seq or Grafana Loki.

For distributed tracing, inject a correlation ID on every request using middleware. Read `X-Correlation-ID` from the incoming header (or generate a new `Guid`), push it into `ILogger`'s ambient scope via `BeginScope`, and echo it back in the response header. Serilog's `LogContext.PushProperty` works identically.

Request logging middleware — either Serilog's `UseSerilogRequestLogging()` or a custom `IMiddleware` — gives you structured per-request entries (method, path, status, elapsed ms) without ASP.NET Core's noisy default host logs. Configure `appsettings.json` to suppress `Microsoft.AspNetCore` at Warning level while keeping your app namespace at Information, so production logs stay clean and actionable.$escape$,
  $escape$// Program.cs
app.Use(async (ctx, next) =>
{
    var correlationId = ctx.Request.Headers["X-Correlation-ID"].FirstOrDefault()
                        ?? Guid.NewGuid().ToString();
    using (logger.BeginScope(new Dictionary<string, object>
        { ["CorrelationId"] = correlationId }))
    {
        ctx.Response.Headers["X-Correlation-ID"] = correlationId;
        await next();
    }
});

// Suppress noisy host logs, keep app logs
builder.Logging.AddFilter("Microsoft.AspNetCore", LogLevel.Warning);
builder.Logging.AddFilter("YourAppNamespace", LogLevel.Information);$escape$,
  $escape$csharp$escape$,
