INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7cfd3d95-50dc-45f2-88dc-dfcb994ac196',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Dev Tooling — Hot Reload, Scaffolding, and dotnet-aspnet-codegenerator$escape$,
  $escape$ASP.NET Core's `dotnet watch` enables Hot Reload without restarting the process — file saves trigger a delta recompile and patch the running IL. For most controller/middleware edits, the app state persists. Rude edits (constructor changes, attribute additions) force a full restart, signaled in the console. Tune behavior in `launchSettings.json` via `"hotReloadEnabled": true` or pass `--no-hot-reload` when profiling.

For scaffolding, `dotnet-aspnet-codegenerator` generates controllers, Razor pages, and EF Core DbContexts from existing models. Install it once per machine: `dotnet tool install -g dotnet-aspnet-codegenerator`. Target a model and DbContext to emit a fully wired Minimal API or MVC controller with CRUD actions — saving 40+ lines of boilerplate per resource.

The `dotnet new` CLI ships first-class templates for Web API, gRPC, SignalR hubs, and Blazor. Custom templates via `dotnet new install <package>` let teams enforce internal conventions — authentication wiring, OpenTelemetry setup, health check endpoints — across every new service from day one.$escape$,
  $escape$# Install scaffolding tool globally
dotnet tool install -g dotnet-aspnet-codegenerator

# Scaffold an API controller for a Product model using AppDbContext
dotnet aspnet-codegenerator controller \
  -name ProductsController \
  -async \
  -api \
  -m Product \
  -dc AppDbContext \
  -outDir Controllers

# Run with hot reload enabled (default in dotnet watch)
dotnet watch run --project ./MyApi/MyApi.csproj$escape$,
  $escape$bash$escape$,
