INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9bfd094a-9a2b-4c26-9aae-b6b1deac504a',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core's Built-In Batteries: What You're Already Shipping Without a Package$escape$,
  $escape$Developers switching from Django, FastAPI, or NestJS often reach for third-party packages to replicate familiar features — but ASP.NET Core already ships most of them. FastAPI's auto-docs? Add `builder.Services.AddOpenApi()` and `app.MapOpenApi()` in .NET 9 — zero Swashbuckle required. NestJS-style decorators map directly to ASP.NET Core attributes: `[Authorize]`, `[RequiredScope]`, `[OutputCache]`, `[RateLimiting]` compose cleanly on Minimal API endpoints or controllers. Phoenix LiveView's server-driven reactivity is Blazor Server over SignalR — components re-render server-side, DOM diffs stream to the client. For Django's batteries-included feel, ASP.NET Core ships `IConfiguration` (layered config with env overrides), `IMemoryCache`, built-in health checks via `AddHealthChecks()`, and `IHttpClientFactory` with polly-backed resilience. The trap is reaching for NuGet when the `Microsoft.AspNetCore.*` namespace already has what you need. Run `dotnet add package` only after checking `WebApplication.CreateBuilder(args)` first.$escape$,
  $escape$var builder = WebApplication.CreateBuilder(args);

builder.Services.AddOpenApi();                          // FastAPI-style auto-docs
builder.Services.AddOutputCache();                      // Built-in response caching
builder.Services.AddRateLimiter(o => o.AddFixedWindowLimiter("api", c => {
    c.Window = TimeSpan.FromMinutes(1);
    c.PermitLimit = 100;
}));
builder.Services.AddHealthChecks().AddNpgSql(connStr);  // DB health endpoint

var app = builder.Build();
app.MapOpenApi();                                       // GET /_openapi/v1.json
app.MapGet("/data", () => Results.Ok())
   .RequireAuthorization()
   .RequireRateLimiting("api")
   .CacheOutput(p => p.Expire(TimeSpan.FromSeconds(30)));

app.Run();$escape$,
  $escape$csharp$escape$,
